<?php
class CustomerController extends Controller { public function index(): void { $cid=$this->companyId(); $stmt=$this->db->prepare('SELECT * FROM customers WHERE company_id=? ORDER BY name'); $stmt->execute([$cid]); $customers=$stmt->fetchAll(); $this->render('customers/index', compact('customers')); } public function save(): void { check_csrf(); $cid=$this->companyId(); $stmt=$this->db->prepare('INSERT INTO customers(company_id,name,email,phone,address) VALUES(?,?,?,?,?)'); $stmt->execute([$cid,$_POST['name'],$_POST['email']??'',$_POST['phone']??'',$_POST['address']??'']); $this->redirect('customers'); }}
